import React, { useState } from 'react';

function WordCloud({ words }) {
  const [selectedWord, setSelectedWord] = useState(null);

  // Expanded container to give them more room to scatter
  const containerWidth = 700;
  const containerHeight = 350;

  // Scattering logic: spread words across the space more evenly
  const placedWords = Object.entries(words).map(([word, count]) => ({
    word,
    fontSize: Math.min(count * 6 + 18, 55),
    // Increased padding (50) to prevent words from hitting the edge
    left: 50 + Math.random() * (containerWidth - 150),
    top: 50 + Math.random() * (containerHeight - 100),
    color: `hsl(${200 + Math.random() * 50}, 70%, 30%)` // Blue-ish tone for clarity
  }));

  if (selectedWord) {
    return (
      <div style={{ padding: '40px', textAlign: 'center', fontFamily: 'sans-serif' }}>
        <h2>Drill Down: {selectedWord}</h2>
        <button onClick={() => setSelectedWord(null)}>Back to Cloud</button>
      </div>
    );
  }

  return (
    <div style={{ 
      position: 'relative', 
      width: `${containerWidth}px`, 
      height: `${containerHeight}px`, 
      margin: '40px auto',
      backgroundColor: '#f8fbff', // Soft cloud-blue tint
      borderRadius: '20px'
    }}>
      {placedWords.map((item) => (
        <span
          key={item.word}
          onClick={() => setSelectedWord(item.word)}
          style={{
            position: 'absolute',
            left: `${item.left}px`,
            top: `${item.top}px`,
            fontSize: `${item.fontSize}px`,
            color: item.color,
            cursor: 'pointer',
            fontWeight: '600',
            fontFamily: 'sans-serif',
            whiteSpace: 'nowrap',
            transition: 'transform 0.2s'
          }}
          onMouseOver={(e) => e.target.style.transform = 'scale(1.1)'}
          onMouseOut={(e) => e.target.style.transform = 'scale(1)'}
        >
          {item.word}
        </span>
      ))}
    </div>
  );
}

export default WordCloud;
